		Version:   0, // 0 means the latest CSS version
	},
	JS: js.Minifier{
		Version: 2022,
	},
	JSON: json.Minifier{},
	SVG: svg.Minifier{
		KeepComments: false,
		Precision:    0, // 0 means no trimming
	},
